INSERT INTO articles (id, slug, title, excerpt, content, category, category_label, featured, image_url, read_time) VALUES
('1', 'coronavirus-psychological-effects', 'كيف نحمي أنفسنا من التداعيات النفسية لفايروس كورونا؟', 'الابتلاءات سنة من سنن الله عز وجل في الحياة، وفي هذا المقال نستعرض أهم الخطوات لحماية صحتنا النفسية في أوقات الأزمات.', E'الابتلاءات سنة من سنن الله عز وجل في الحياة. ومع انتشار فايروس كورونا المستجد، تزايدت المخاوف والقلق لدى كثير من الناس، مما يستدعي منا الاهتمام بصحتنا النفسية كما نهتم بصحتنا الجسدية.\n\nإن الخوف المفرط والقلق المستمر يضعف المناعة النفسية والجسدية على حد سواء. لذلك من المهم أن نتعامل مع هذه الأزمة بوعي وحكمة.\n\n**خطوات عملية لحماية الصحة النفسية:**\n\n1. **تقليل متابعة الأخبار السلبية** - حدد أوقاتاً معينة لمتابعة المستجدات من مصادر موثوقة فقط.\n\n2. **ممارسة تقنيات الاسترخاء** - التنفس العميق والتأمل يساعدان على تخفيف القلق.\n\n3. **الحفاظ على الروتين اليومي** - النظام والانضباط يمنحان شعوراً بالأمان والاستقرار.\n\n4. **التواصل الاجتماعي** - حافظ على تواصلك مع أحبائك حتى لو عن بُعد.\n\n5. **ممارسة الرياضة** - النشاط البدني من أفضل مضادات القلق والاكتئاب.\n\n6. **التغذية الروحية** - القرب من الله والدعاء والذكر يمنح الطمأنينة والسكينة.\n\n7. **استثمار الوقت** - اجعل من هذه الفترة فرصة لتعلم مهارات جديدة أو تطوير ذاتك.\n\nتذكر أن الأزمات مؤقتة، وأن قدرتنا على التكيف والصبر هي ما يصنع الفرق في حياتنا.', 'psychology', 'علم النفس', true, 'https://images.unsplash.com/photo-1544027993-37dbfe43562a?w=800&h=400&fit=crop', 5),
('2', 'atychiphobia', 'هل تعاني من الأتيكوفوبيا؟', 'بالأمل نحيا وبالعمل تحيا أنفسنا. الأتيكوفوبيا أو الخوف من الفشل، حالة نفسية تعيق الكثيرين عن تحقيق أحلامهم.', E'بالأمل نحيا وبالعمل تحيا أنفسنا. الأتيكوفوبيا هو الخوف المرضي من الفشل الذي يتحول لعقبة تمنع صاحبها من الإقدام والمبادرة خوفاً من الإخفاق.\n\nيُعرّف بأنه "الخوف غير العقلاني من الفشل الذي يجعل صاحبه يتقوقع ويتجنب خوض تجارب جديدة حفاظاً على صورته أمام الآخرين."\n\n**الأعراض الرئيسية:**\n- القلق الشديد عند مواجهة تحديات جديدة\n- تجنب المبادرات والمشاريع خوفاً من النتائج\n- انتقاء التجارب الفاشلة من الماضي وتعميمها\n- الشخصية المترددة التي تلتقط كل إخفاق لتعزز خوفها\n\n**الأسباب:**\nقد تكون بذرة هذا الخوف نمت أثناء خوف الوالدين من إخفاق الابن وتحذيره المستمر. كما أن الشدة والتدقيق الشديد على السلوكيات والتركيز على النجاح أكثر من التنمية الشخصية تُنشئ المثالية والخوف من خوض غير المألوف.\n\n**أساليب الحد من هذا الخوف:**\n\n1. **تصحيح النظرة للفشل** على أنه إخفاق في زاوية معينة لا في كافة مناحي الحياة.\n\n2. **مراقبة الحوار الذاتي** فالسلبي منه يعيد بشكل مستمر كل قصص الحياة السلبية.\n\n3. **الاطلاع على سير العظماء والناجحين** وكيف أن مسيرتهم رغم نجاحها الباهر تخللها الإخفاق.\n\n4. **إياك وتجنب المبادرة والإقدام** لتجنب الفشل لأنك بتجنبها حكمت على حياتك كلها بالفشل.\n\n5. **خطط لأسوأ ما يمكن أن يحدث** بمعنى أن تبني منهجاً بديلاً في حالة الإخفاق.\n\n6. **الغمر والمواجهة** لما تخافه بخطوات صغيرة تعزز نجاحك.\n\n7. **تصحيح الأفكار المتطرفة** التي تقود للسلبية والخوف.\n\nتأكد أن كل إخفاق في تجربة ما يعزز نسبة نجاحك في المحاولات القادمة.', 'psychology', 'علم النفس', true, 'https://images.unsplash.com/photo-1508963493744-76fce69379c0?w=800&h=400&fit=crop', 7),
('3', 'fathers-parenting-touches', 'لمسات الأب التربوية', 'اختلف إيقاع الحياة بشكل عام في السنوات الأخيرة. يقف الأب الواعي متسائلاً عن دوره التربوي تجاه أبنائه.', E'اختلف إيقاع الحياة بشكل عام في السنوات الأخيرة عنها قبل عدة سنوات في كثير من الأمور.\n\nيقف الأب الواعي كثيراً ويتساءل ما دوري التربوي تجاه أبنائي؟\n\nحقيقة إن التربية وظيفة كلا الأبوين. تظل الأم المحور الرئيسي في التربية لما هيأها الله عليه من مرونة وحنان.\n\n**يمكن تقسيم مشاركة الأب التربوية لنوعين:**\n\n**النوع الأول: المجهود التربوي الظاهر** عن طريق سلوكيات ظاهرة كالحوار مع الأولاد وتقويم سلوكياتهم.\n\n**النوع الثاني: المجهود التربوي غير الظاهر** من خلاله بشكل مباشر، ومن أهم أساليبه القدوة.\n\n**التربية غير الظاهرة تنقسم لثلاثة أقسام:**\n\n**التربية بالتفاهم والتعاون:** من خلال التفاهم مع الأم بتوفير بيئة أسرية مستقرة.\n\n**التربية بالعطاء والمنع:** تتمركز في بذل العاطفة والعطاء المادي المتوازن.\n\n**التربية بالقدوة:** من خلال السلوك الإيجابي والامتناع عن السلوك السلبي.', 'parenting', 'التربية', true, 'https://images.unsplash.com/photo-1536640712-4d4c36ff0e4e?w=800&h=400&fit=crop', 6),
('4', 'marital-hibernation', 'السبات الزوجي', 'يُعرف السبات بأنه حالة من الخمول السلوكي وانخفاض في الوظائف الحيوية. السبات الزوجي هو سبات من نوع آخر.', E'يُعرف السبات بأنه حالة من الخمول السلوكي وانخفاض في الوظائف الحيوية.\n\nالسبات الزوجي هو سبات لكن من نوع آخر، له نفس الهدف تقريباً وهو الحفاظ على الحياة الزوجية.\n\n**وينتج هذا السبات الزوجي من عدة أسباب:**\n\n**الأول:** الروتين في الحياة الزوجية.\n**والثاني:** كثرة المشكلات الزوجية.\n\n**خطة التغيير تبدأ من:**\n- تغيير في طريقة التفكير تجاه الزوج الآخر\n- التغيير في سلوك الزوجين أو أحدهما تجاه الآخر\n\nإن الهدف هو الوصول بالحياة الزوجية للاستقرار لا للرتابة.', 'relationships', 'العلاقات الزوجية', false, 'https://images.unsplash.com/photo-1516589178581-6cd7833ae3b2?w=800&h=400&fit=crop', 8),
('5', 'psychological-fragility', 'الهشاشة النفسية', 'ربما قد جربت مرةً أن تضغط بقوة على حبة جوز صلبة لبعض الوقت وبشكل متواصل؛ لتجد أنها قد أصبحت أقل صلابة.', E'ربما قد جربت مرةً أن تضغط بقوة على حبة جوز صلبة لبعض الوقت، وبشكل متواصل؛ لتجد أنها قد أصبحت أقل صلابة ومقاومة للضغط بل وأكثر هشاشة.\n\nيُشير مصطلح الهشاشة النفسية إلى "الحالة غير المتزنة التي يعاني منها البعض مما تجعلهم ضعاف النفس قابلين للتأثر بالعوامل الخارجية."\n\n**الأعراض:**\n- فقدان الهوية والتأثر الشديد بالأحداث البسيطة\n- الإحباط المستمر وإلقاء المسؤولية على الآخرين\n- القلق والتفكير في دوائر مغلقة\n\n**سبل الوقاية والعلاج:**\n- المرونة في التعامل مع الأحداث الحياتية\n- رسم مسار واضح للأهداف لتعميق الثقة بالنفس\n- تحديد الحدود الشخصية والاجتماعية\n- التركيز على التفكير العقلاني كأساس للقوة النفسية\n- التعلق بالله والحرص على رضاه', 'psychology', 'علم النفس', true, 'https://images.unsplash.com/photo-1474631245212-32dc3c8310c6?w=800&h=400&fit=crop', 6),
('6', 'stockholm-syndrome', 'متلازمة ستوكهولم', 'تُنسب متلازمة ستوكهولم إلى العاصمة السويدية نتيجة حادثة سرقة حدثت في المدينة منذ عشرات السنين.', E'تُنسب متلازمة ستوكهولم إلى العاصمة السويدية، التي اقتبست هذه المتلازمة منها اسمها.\n\nورغم أن المقصود بمتلازمة ستوكهولم حصول التعاطف بين شخصين أحدهما يُلحق الضرر بالآخر ويؤذيه مع الدفاع الشديد عنه، غير أننا نعيشها اليوم في مواقف كثيرة.\n\n**أمثلة معاصرة:**\n- منح الأطفال أجهزة ذكية رغم معرفتنا بأخطارها\n- التمسك بالعادات الضارة كالتدخين والسهر المستمر\n- الإدمان الإلكتروني على الهواتف الذكية\n\nأصعب أنواع متلازمة ستوكهولم هي "أن تكون أنفسنا هي عدوتنا الرئيسة".', 'psychology', 'علم النفس', false, 'https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?w=800&h=400&fit=crop', 5),
('7', 'secret-code-parenting', 'التربية بأسلوب الشفرة السرية', 'تعددت الأساليب والتربية هي الهدف. أسلوب الشفرة السرية يقدم طريقة ذكية لتصحيح سلوك الأبناء دون إحراج.', E'تعددت الأساليب والتربية هي الهدف.\n\n**الأسلوب المقترح:**\nالطريقة باختصار هي أن يكون هناك "شفرة معينة بين الوالدين وأحد الأبناء كأن تكون إشارة باليد أو كلمة تبدو عادية".\n\n**الإيجابيات:**\n- لا يشعر الابن بالنقد لأنه اتفق مسبقاً مع والديه\n- تعزز الصداقة بينهما\n- تشعره بأن والديه يواكبان احتياجاته', 'parenting', 'التربية', false, 'https://images.unsplash.com/photo-1476234251651-f353703a034d?w=800&h=400&fit=crop', 4),
('8', 'psychological-marathon', 'الماراثون النفسي', 'مصطلح يركز على لياقتنا النفسية لتحقيق إنجازات نفسية نبني بها شخصياتنا بدلاً من التركيز على الجانب الرياضي فقط.', E'مصطلح الماراثون النفسي يركز على "لياقتنا النفسية؛ لتحقيق إنجازات نفسية نبني بها شخصياتنا".\n\n**مميزاته:**\n- غير مقيد بزمان أو مكان\n- تحدي شخصي مع الذات\n- لا يوجد خاسرون فيه\n\n**المبادئ الأساسية:**\n1. **تدعيم الثقة بالنفس**\n2. **التفكير الإيجابي**\n3. **الرضا عن الذات**\n4. **التغذية الروحية**\n5. **الاستعداد النفسي**\n6. **الصبر والاستمرارية**', 'self-development', 'تطوير الذات', false, 'https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=800&h=400&fit=crop', 5),
('9', 'five-star-parenting', 'تربية خمس نجوم', 'احتلت التربية مكانة مهمة في نقاشات المجالس وأصبحت محور اهتمام معظم البيوت. خمسة محاور أساسية للتربية المتميزة.', E'احتلت التربية مكانة مهمة في نقاشات المجالس وأصبحت محور اهتمام معظم البيوت.\n\n**المحاور الخمسة للتربية:**\n1. **تفهم وإشباع احتياجات الأبناء**\n2. **تفهم شخصياتهم**\n3. **التواصل والحوار معهم**\n4. **تقويم سلوكياتهم**\n5. **تنمية قدراتهم ومواهبهم**\n\nالتربية المثالية نسبية واجتهادية تختلف حسب الظروف الأسرية.', 'parenting', 'التربية', false, 'https://images.unsplash.com/photo-1609220136736-443140cffec6?w=800&h=400&fit=crop', 5),
('10', 'psychological-displacement', 'الإزاحة النفسية.. ترجمان غضبك', 'كثيراً ما نتعرض لمواقف هجومية تحمل شحنات غاضبة وعدائية ممن حولنا فنقف أمام هذه المواقف متعجبين.', E'كثيراً ما نتعرض لمواقف هجومية تحمل شحنات غاضبة وعدائية ممن حولنا.\n\nالإزاحة النفسية هي تفريغ الشحنات السلبية في شخص أو هدف آخر.\n\n**أمثلة:**\n- عقاب الأطفال بدون مبرر\n- رمي الهاتف بقوة بعد مكالمة مزعجة\n- إغلاق الباب بقوة بعد خلاف عائلي\n\n**سبل التعامل:**\n- امتصاص غضب الشخص بالهدوء والتعاطف\n- الحوار الهادئ ومناقشة المشكلات\n- تحويل الطاقة السلبية لسلوكيات إيجابية', 'psychology', 'علم النفس', false, 'https://images.unsplash.com/photo-1493836512294-502baa1986e2?w=800&h=400&fit=crop', 5),
('11', 'body-language', 'لغة الجسد.. اللغة الصامتة', 'تُعتبر لغة الجسد من أقوى وسائل الاتصال بين البشر، حيث تُعد لغة مشتركة على اختلاف الأجناس واللغات.', E'تُعتبر لغة الجسد من أقوى وسائل الاتصال بين البشر.\n\nذكرت الدراسات أن التواصل يتم 7% بالكلمات و38% بنبرات الصوت و55% عن طريق لغة الجسد.\n\n**نقاط مهمة للفهم الصحيح:**\n- تفسير الإيماءات مجتمعة وليس منفصلة\n- ربط الإيماءات باللغة اللفظية\n- قراءة الحركات في سياق الموقف\n\nقراءة لغة الجسد توفر قياساً دقيقاً للحالة المزاجية.', 'psychology', 'علم النفس', false, 'https://images.unsplash.com/photo-1573497620053-ea5300f94f21?w=800&h=400&fit=crop', 4),
('12', 'one-minute-parenting', 'تربية الدقيقة الواحدة', 'يقدم الدكتور سبنسر جونسون أسلوباً تربوياً حديثاً يعتمد على دقيقة واحدة فقط لتقويم سلوك الطفل بحب وحزم.', E'يقدم الدكتور "سبنسر جونسون" في كتابه أسلوب تربوي حديث يعتمد على:\n\n**المرحلة الأولى (النصف الأول من الدقيقة):**\n- التوبيخ السريع بعد الخطأ مباشرة\n- توضيح التصرف الخاطئ تحديداً\n- إظهار عدم الرضا عن السلوك بوضوح\n\n**المرحلة الثانية (النصف الثاني من الدقيقة):**\n- الهدوء واللمس الحنون\n- تأكيد حب الوالد للطفل\n- التأكيد على أن الطفل "شخص طيب" لكن السلوك مرفوض\n\nالمرجع: كتاب "كيف تكون أحسن مربي في العالم" - تأليف: محمد سعيد مرسي', 'parenting', 'التربية', false, 'https://images.unsplash.com/photo-1503454537195-1dcabb73ffb9?w=800&h=400&fit=crop', 3)
INSERT INTO quotes (id, text) VALUES
('1', 'الكتابة صورة مختصرة من شخصيتك، تظهر بأسلوبك وتُنقش بقلمك.'),
('2', 'الرضا عن الذات مغناطيس النجاح.'),
('3', 'لا تكن عدو نفسك بحرمانها من معرفة مشكلتها وعلاجها.'),
('4', 'بعض المشكلات النفسية هي مجرد دلالات لسوء تفهمك لذاتك والعالم من حولك.'),
('5', 'إن أهم ما يحتاجه المريض النفسي هو إعادة برمجة حياته وأسلوب تفكيره بشكل أفضل.'),
('6', 'لن تجد التغيير مادمت تبحث عنه خارج نفسك.'),
('7', 'الموت الحقيقي لا يكون بانتهاء الحياة إنما بنفاذ الأمل في الحياة.'),
('8', 'الإنسان السوي يترك بصمته في الحياة ولا يجعل مشكلات الحياة تترك بصمتها فيه.'),
('9', 'الاستشارة هي البذرة التي إن استثمرتها أنبتت شجرة تُظلك.'),
('10', 'تفكيرك هو محركك وجودة المخرجات السلوكية من جودة هذا المحرك.. فأحسن اختيار محركك.'),
('11', 'لن نستطيع تعديل سلوكيات أبناءنا السلبية إلا إذا تخلصنا منها أولاً.'),
('12', 'كبت المشاعر السلبية كثيراً ما يتسبب بمشكلات نفسية أو عضوية.. فاحرص على تفريغها والتخلص منها.'),
('13', 'ابحث عن مكان نفسك داخلك قبل أن تبحث عنها حولك.'),
('14', 'الحياة كالكتاب تُدون من خلالها خبراتك وذكرياتك.. فانتبه لجودة ما تكتب.'),
('15', 'في بعض التغافل علاج لسلوكيات الأبناء.. وراحة لأنفسنا لتجنب المشكلات مع من حولنا.'),
('16', 'السعادة تكمن في التركيز على ما نملكه والتغافل عما نفتقده.')
INSERT INTO consultations (id, name, email, type, text, status, answer, created_at, answered_at) VALUES
('archive-1', '', '', 'psychological', 'أعاني من خفقان بالقلب وبعد عدة أشهر صارت تأتيني بشكل شبه يومي وبدأت تزيد الأعراض، أحس بشيء يقف بحلقي. ذهبت للمستشفى وعملت تحاليل، لكن حتى مع تناول الأدوية ما تحسنت حالتي. دائماً أحس بكتمة وما أقدر آخذ نفساً كافياً، وإذا أحسست بالكتمة أحس بدوخة وبرودة بالأطراف وخفقان بالقلب وألم بالصدر وخوف شديد.', 'archived', 'تشير الأعراض الموصوفة إلى نوبات الذعر الناتجة عن القلق النفسي. العلاج يركز على تقنيات الاسترخاء وتنظيم التنفس والعلاج المعرفي السلوكي لتقليل التوتر والسيطرة على الأفكار السلبية. من المهم التأكد من سلامة الجانب العضوي أولاً، ثم التركيز على الجانب النفسي من خلال متخصص.', '2024-01-15', '2024-01-16'),
('archive-2', '', '', 'psychological', 'أعاني من صعوبة في التركيز أثناء الدراسة والعمل. أشعر بأن ذهني مشتت دائماً ولا أستطيع إنجاز مهامي بالشكل المطلوب. هل هذا طبيعي؟', 'archived', 'التشتت وصعوبة التركيز قد يكون ناتجاً عن عدة عوامل منها: الضغوط النفسية، قلة النوم، الإفراط في استخدام الأجهزة الإلكترونية، أو القلق. يُنصح بتنظيم وقت النوم، تقليل المشتتات، ممارسة تمارين التركيز والتأمل، وتقسيم المهام الكبيرة إلى مهام صغيرة قابلة للإنجاز.', '2024-02-10', '2024-02-11'),
('archive-3', '', '', 'self-development', 'أشعر بضغط نفسي كبير من متطلبات الحياة والعمل والأسرة. لا أجد وقتاً لنفسي وأشعر بالإرهاق المستمر. كيف أتعامل مع هذه الضغوط؟', 'archived', 'إدارة الضغوط تبدأ بتحديد مصادرها وترتيب الأولويات. من المهم تخصيص وقت يومي للراحة والاسترخاء حتى لو كان قصيراً. ممارسة الرياضة والتغذية الصحية والنوم الكافي أسس مهمة. كما أن التواصل مع شخص موثوق والتعبير عن المشاعر يخفف الحمل النفسي. تذكر أن طلب المساعدة المتخصصة ليس ضعفاً بل قوة.', '2024-03-05', '2024-03-06')
INSERT INTO guestbook_entries (id, name, message, status, created_at) VALUES
('gb-1', 'زائرة', 'موقع رائع ومفيد جداً. استفدت كثيراً من المقالات التربوية. جزاكم الله خيراً.', 'approved', '2024-01-20'),
('gb-2', 'أم محمد', 'شكراً على المحتوى القيم. مقال تربية خمس نجوم ساعدني كثيراً في التعامل مع أطفالي.', 'approved', '2024-02-15'),
('gb-3', 'باحثة نفسية', 'محتوى علمي ممتاز ومبسط في نفس الوقت. أتمنى المزيد من المقالات في مجال الصحة النفسية.', 'approved', '2024-03-10')
